sql:
SELECT influencer_id, topic
FROM influencers
INNER JOIN users ON influencers.user_id = users.user_id;

SELECT stock_id, MAX(open_price) AS highest_open_price, MIN(close_price) AS lowest_close_price
FROM stock_market_data
GROUP BY stock_id;

SELECT COUNT(*) as tweet_count
FROM tweet_stock_mentions
WHERE stock_id = (SELECT stock_id FROM stock_symbols WHERE stock_symbol = '$AMZN');

SELECT AVG(t.engagement_score) AS avg_engagement_score
FROM tweets t
WHERE t.likes = (SELECT MAX(likes) FROM tweets);

SELECT tweets.text, sentiments.sentiment_score
FROM tweets
JOIN sentiments ON tweets.tweet_id = sentiments.tweet_id;

SELECT tweet_id
FROM sentiments
WHERE sentiment_score = (
    SELECT MAX(sentiment_score)
    FROM sentiments
);

SELECT impact_score 
FROM news_events 
WHERE event_id = 0;

SELECT event_id, event_date, event_description, impact_score
FROM news_events
WHERE impact_score = (SELECT MAX(impact_score) FROM news_events);
